const body = $input.first().json.body || {};
const message = (body.message || '').trim();
const session_id = (body.session_id || 'rag-default').trim();

// Health-check: отдаём pong без вызова LLM
if (message === 'ping') {
  return [{json: {valid: 0, error: 'pong'}}];
}

// __AUTH_PATCH_V1__
// === SSO Phase 3: token presence check ===
// Без токена → auth_required, фронт redirect на /login.html
const __token = String((body && body.token) || '').trim();
const __userName = String((body && body.user_name) || '').trim().slice(0, 80);
if (!__token || !/^[a-f0-9]{64}$/.test(__token)) {
  return [{json: {valid: 0, error: 'auth_required', auth_required: true}}];
}


if (!message || message.length < 2) {
  return [{json: {valid: 0, error: 'Введите сообщение'}}];
}

// Защита от SQL-инъекций через session_id
if (!/^[a-zA-Z0-9_-]{3,64}$/.test(session_id)) {
  return [{json: {valid: 0, error: 'session_id содержит недопустимые символы'}}];
}

if (message.length > 100000) {
  return [{json: {valid: 0, error: 'Слишком длинный запрос (максимум 100000 символов)'}}];
}

const __docGet = String((body && body.doc_get) || '').trim();
const __focusDoc = String((body && body.focus_doc) || '').trim().slice(0, 400);
return [{json: {valid: 1, message: message, session_id: session_id, token: __token, doc_get: __docGet, user_name: __userName, focus_doc: __focusDoc}}];

const message = $('Агрегация').first().json.message;
const historyContext = $('Агрегация').first().json.historyContext || '';
const session_id = $('Агрегация').first().json.session_id || 'rag-default';
const lower = message.toLowerCase();

// R8.82: клик по имени документа (фронт шлёт doc_get='source|id') — показать
// ПОЛНЫЙ контент из БД, без LLM и без обычной классификации.
const __docGet = String(($('Агрегация').first().json.doc_get) || '').trim();
if (__docGet) {
  const __bar = __docGet.indexOf('|');
  const __src = __bar >= 0 ? __docGet.slice(0, __bar) : 'internal';
  const __did = __bar >= 0 ? __docGet.slice(__bar + 1) : __docGet;
  return [{ json: { message, mode: 'get_document', doc_source: __src, doc_id: __did, historyContext, session_id } }];
}

// NEW-3: явное обнаружение «покажи / какие документы есть» — для таких
// запросов embedding-поиск не работает (вопрос не содержит контента ни
// одного конкретного документа). Используем SELECT DISTINCT filename.
const listIndicators = [
  'какие документ', 'какие файл', 'список документ', 'список файл',
  'покажи документ', 'покажи файл', 'покажи все документ', 'покажи все файл',
  'что загружен', 'что есть в баз', 'что есть в документ', 'документы в базе', 'файлы в базе',
  'перечисли документ', 'перечисли файл',
  'имена документ', 'имена файл', 'названия документ', 'названия файл',
  'все документ', 'все файл',
  'сколько документ', 'сколько файл',
  'количество документ', 'количество файл', 'кол-во документ', 'кол-во файл', 'число документ', 'число файл',
  'все мои документ', 'все мои файл', 'покажи мои документ', 'мои документ', 'мои файл', 'есть документ', 'есть файл', 'что у меня в баз', 'что в баз', 'покажи всё', 'покажи все'
];
for (const ind of listIndicators) {
  if (lower.includes(ind)) {
    return [{ json: { message, mode: 'list_documents', historyContext, session_id } }];
  }
}

// R5 BUG-3 (RAG hallucinates docs in tables): просьба «представь документы
// в виде таблицы» / «список документов в таблицу» / «таблица документов» —
// это запрос про БД, не про содержание. Маршрутизируем в list_documents.
const tablePatterns = [
  /в\s+виде\s+таблиц/,
  /таблиц[ауеыйо]*\s+(документ|файл|загруж)/,
  /(документ|файл|загруж)\w*\s+\w*\s*(в\s+таблиц|таблицей|списком)/,
  /представ\w*\s+(документ|файл|базу)/,
  /выведи\s+(документ|файл|список)/,
  /оформи\s+(документ|файл)\w*\s+(в\s+таблиц|таблицей)/
];
for (const re of tablePatterns) {
  if (re.test(lower)) {
    return [{ json: { message, mode: 'list_documents', historyContext, session_id } }];
  }
}

const docKeywords = [
  'документ', 'договор', 'акт', 'контракт', 'соглашени',
  'коммерческ', 'предложени', 'кп ', 'доверенност',
  'записк', 'протокол', 'приказ', 'заявлени',
  'шаблон', 'бланк', 'образец', 'форм',
  'найди в документ', 'что написано', 'что сказано',
  'о чём документ', 'о чем документ', 'содержание документ',
  'загруженн', 'файл', 'текст документ',
  'пункт', 'параграф', 'раздел', 'глав',
  'срок', 'оплат', 'условия', 'реквизит',
  'составь', 'подготовь', 'создай документ', 'напиши документ',
  'база знаний', 'база документ', 'найди информаци',
  'процитируй', 'цитат', 'выдержк',
  'регламент', 'инструкци', 'положени', 'устав',
  'накладн', 'счёт', 'счет-фактур', 'акт выполненн'
];

let isDoc = false;

for (const kw of docKeywords) {
  if (lower.includes(kw)) { isDoc = true; break; }
}

// Дополнительная проверка: вопрос о содержимом
if (!isDoc && message.length > 15) {
  const contentIndicators = ['что написано', 'что сказано', 'о чём', 'о чем', 'найди в', 'процитируй'];
  const contentEntities = ['документ', 'файл', 'договор', 'акт', 'контракт'];
  const hasQuestion = contentIndicators.some(q => lower.includes(q));
  const hasEntity = contentEntities.some(e => lower.includes(e));
  if (hasQuestion && hasEntity) isDoc = true;
}

// R8.89: открыт документ (focus_doc) — сильный сигнал «вопрос по документу».
// Роутим в document-режим (кроме явной болтовни/приветствий), чтобы поиск шёл
// по последнему просмотренному документу.
const __m = String(message || '').trim().toLowerCase();
const __small = ['привет','здравствуй','здравствуйте','спасибо','пожалуйста','пока','как дела','ок','окей','ладно','ага','угу','да','нет','хай'];
const __isSmall = __small.some(w => __m === w || __m.startsWith(w + ' ') || __m.startsWith(w + ',') || __m.startsWith(w + '!'));
const __focus = String(($('Агрегация').first().json.focus_doc) || '').trim();
if (__focus && !__isSmall) isDoc = true;

if (!isDoc) {
  return [{ json: { message, mode: 'general', historyContext, session_id } }];
}

return [{ json: { message, mode: 'document', historyContext, session_id } }];

try {
  const raw = $input.first().json;
  if (raw.error) {
    return [{ json: { response: 'GigaChat не отвечает. Проверьте подключение.' } }];
  }
  const text = raw && raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0] && raw.output[0].content[0].text;
  if (!text) {
    return [{ json: { response: 'Пустой ответ от LLM. Попробуйте ещё раз.' } }];
  }
  return [{ json: { response: text.trim() } }];
} catch(e) {
  return [{ json: { response: 'Ошибка обработки.' } }];
}

// Готовим вектор для поиска похожих документов в PGVector.
// SQL формируется в Postgres-ноде через queryReplacement ($1::vector) —
// здесь нужно только извлечь вектор и проверить его валидность.
try {
  const data = $input.first().json;

  if (data.error) {
    return [{ json: { search_sql: null, fallback: 'Ошибка получения эмбеддинга. Поиск по документам недоступен.' } }];
  }

  let vector = null;
  if (data.data && Array.isArray(data.data) && data.data[0] && data.data[0].embedding) {
    vector = data.data[0].embedding;
  } else if (data.embedding && Array.isArray(data.embedding)) {
    vector = data.embedding;
  } else if (Array.isArray(data) && data.length > 0 && typeof data[0] === 'number') {
    vector = data;
  }

  if (!vector || vector.length === 0) {
    return [{ json: { search_sql: null, fallback: 'Не удалось получить вектор вопроса. Попробуйте переформулировать.' } }];
  }

  // Defense-in-depth: проверяем что вектор — массив конечных чисел.
  if (!vector.every(v => typeof v === 'number' && Number.isFinite(v))) {
    return [{ json: { search_sql: null, fallback: 'Невалидный вектор от эмбеддера.' } }];
  }

  // R8.89: «акцент на последний просмотренный документ». Фронт шлёт focus_doc=
  // 'source|id'. Если он задан — поиск ограничиваем этим документом (тот источник,
  // другой возвращает пусто). SQL строим тут (а не в выражении Postgres-ноды),
  // чтобы избежать кошмара экранирования в {{ }}.
  const __fd = String(($('Валидация').first().json.focus_doc) || '').trim();
  const __fbar = __fd.indexOf('|');
  const focus_source = __fd ? (__fbar >= 0 ? __fd.slice(0, __fbar) : 'internal') : '';
  const focus_id = __fd ? (__fbar >= 0 ? __fd.slice(__fbar + 1) : __fd) : '';
  const __vs = '[' + vector.join(',') + ']';
  const EMPTY_INT = "SELECT '' as chunk_text, '' as filename, 0 as similarity, 'наш' as source";
  const EMPTY_EXT = "SELECT '' as chunk_text, '' as filename, 0 as similarity, 'внешний' as source";
  const BASE_INT = "SELECT filename, chunk_index, chunk_text, 1 - (embedding <=> $1::vector) AS similarity, 'наш' AS source FROM documents";
  const BASE_EXT = 'SELECT file_name AS filename, chunk_index, "text" AS chunk_text, 1 - ("vector" <=> $1::vector) AS similarity, \'внешний\' AS source FROM _vectordocuments.v_general';
  let internal_sql, internal_params, external_sql, external_params;
  if (focus_source === 'internal') {
    internal_sql = BASE_INT + ' WHERE filename = $2 ORDER BY embedding <=> $1::vector LIMIT 5';
    internal_params = [__vs, focus_id];
    external_sql = EMPTY_EXT; external_params = [];
  } else if (focus_source === 'external') {
    internal_sql = EMPTY_INT; internal_params = [];
    external_sql = BASE_EXT + ' WHERE document_id::text = $2 ORDER BY "vector" <=> $1::vector LIMIT 5';
    external_params = [__vs, focus_id];
  } else {
    internal_sql = BASE_INT + ' ORDER BY embedding <=> $1::vector LIMIT 5';
    internal_params = [__vs];
    external_sql = BASE_EXT + ' ORDER BY "vector" <=> $1::vector LIMIT 5';
    external_params = [__vs];
  }
  return [{ json: { search_sql: true, vector_str: __vs, vector_size: vector.length, focus_source, focus_id, internal_sql, internal_params, external_sql, external_params } }];
} catch (e) {
  return [{ json: { search_sql: null, fallback: 'Ошибка обработки эмбеддинга: ' + e.message } }];
}

const items = $input.all().map(item => item.json);
const buildSearch = $('Построить поиск').first().json;

// Если эмбеддинг упал — fallback
if (buildSearch.fallback) {
  return [{json: {has_docs: false, documents: '', fallback_message: buildSearch.fallback}}];
}

// Если Postgres вернул ошибку (БД упала / SQL-syntax), нода с
// onError:continueRegularOutput отдаёт {error: '...'} вместо рядов.
// Без этой проверки фильтр ниже отсеет всё → пользователь увидит
// «не нашли документов», хотя на самом деле упала БД. Отличаем явно.
if (items.length > 0 && items[0] && items[0].error) {
  console.log('[rag] ошибка запроса documents:', items[0].error); return [{json: {has_docs: false, documents: '', fallback_message: 'База документов временно недоступна. Повторите запрос через минуту.'}}];
}

// Жёсткий порог similarity 0.5 (раньше был 0.3 — пропускал мусорные
// результаты, на которых LLM галлюцинировала и выдумывала «факты из файла»).
const MIN_SIMILARITY = 0.5;

const docs = items.filter(item =>
  item && item.chunk_text && item.chunk_text.trim && item.chunk_text.trim().length > 0 &&
  (item.similarity === undefined || item.similarity >= MIN_SIMILARITY)
);

if (docs.length === 0) {
  return [{json: {has_docs: false, documents: '', fallback_message: 'В базе документов не найдено информации по вашему запросу. Загрузите нужные документы через страницу загрузки.'}}];
}

// R5 BUG-4 fix: убран spread-check (top.similarity - tail.similarity < 0.05).
// Он отвергал валидные кейсы где все найденные чанки одинаково релевантны
// (типично для xlsx-таблиц с похожими строками или серии шаблонов договоров).
// Юзер просил «не отказывайся отвечать через эту отговорку».
// MIN_SIMILARITY уже фильтрует мусор; дополнительный гейт лишний.

var maxSim = Math.max.apply(null, docs.map(function(d){ return typeof d.similarity === 'number' ? d.similarity : 1; })); var lowConfidence = maxSim < 0.6; const context = docs.map((d, i) => {
  const src = ''; // R8.89: имя файла НЕ кладём в контекст — LLM не должна писать название документа
  return (i + 1) + '.' + src + '\n' + d.chunk_text;
}).join('\n\n');

var finalContext = lowConfidence ? ('ВНИМАНИЕ: найденные фрагменты слабо релевантны — начни ответ с предупреждения «Документы могут быть недостаточно релевантны, проверьте оригинал» и отвечай осторожно. ' + context) : context; return [{json: {has_docs: true, documents: finalContext, doc_count: docs.length, low_confidence: lowConfidence, filenames: [...new Set(docs.map(d => d.filename).filter(Boolean))]}}];

try {
  const raw = $input.first().json;
  if (raw.error) {
    return [{ json: { response: 'Не удалось обработать запрос к документам. Попробуйте переформулировать.' } }];
  }
  const text = raw && raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0] && raw.output[0].content[0].text;
  if (!text) {
    return [{ json: { response: 'Пустой ответ от LLM. Попробуйте ещё раз.' } }];
  }
  return [{ json: { response: text.trim() } }];
} catch(e) {
  return [{ json: { response: 'Ошибка генерации ответа.' } }];
}

const historyRows = $input.all().reverse();
let historyContext = '';
if (historyRows.length > 0) {
  const lines = historyRows.map(item => {
    const role = item.json.role === 'user' ? 'Пользователь' : 'Ассистент';
    return role + ': ' + (item.json.content || '');
  });
  historyContext = 'История диалога:\n' + lines.join('\n') + '\n\n';
}
const v = $('Валидация').first().json;
return [{json: {message: v.message, session_id: v.session_id, historyContext: historyContext, doc_get: (v.doc_get || ''), user_name: (v.user_name || ''), focus_doc: (v.focus_doc || '')}}];

