const item = $input.first();
const data = item && item.json ? item.json : null;
const src = $('Валидация').first().json;
// PostgreSQL сбой: data может быть null или содержать .error поле — НЕ
// помечаем как unauthorized, иначе юзер видит ложный auth_required редирект.
if (data && data.error) {
  return [{ json: { token_valid: false, response: 'error', error: 'database_unavailable' } }];
}
if (!data || !data.user_id) {
  return [{ json: { token_valid: false, response: 'error', error: 'unauthorized', auth_required: true } }];
}
return [{ json: { ...src, token_valid: true, user_id: data.user_id } }];

// v_general хранит ЧАНКИ; «Список внешний» группирует их по document_id (GROUP BY).
// Наша documents — чанки, уже сгруппированные по filename в SQL.
// Поэтому НЕ дедупим по filename здесь: дедуп схлопнул бы внешние
// документы с пустыми/одинаковыми именами. Просто фильтруем
// error-строки; каждая входная строка = ОДИН документ (чанки уже сгруппированы в SQL).
const all = $input.all().map(i => i.json);
const rows = all.filter(r => r && !r.error && r.filename && String(r.filename).trim());

// R8.81: чистим кривые имена из БД (особенно офисная rel_db). В file_name лежат
// полные пути: /app/site/uploads/.../docx/Пояснительная.docx или
// D:\project\...\docx\Шаблон_ответа_13.docx. Берём только имя файла (после
// последнего / или обратного слэша) и меняем '_' на пробел (там '_' вместо пробела).
function cleanName(raw) {
  var s = String(raw).trim();
  var cut = Math.max(s.lastIndexOf('/'), s.lastIndexOf('\\'));
  if (cut >= 0) s = s.slice(cut + 1);
  s = s.split('_').join(' ');
  while (s.indexOf('  ') !== -1) s = s.split('  ').join(' ');
  return s.trim() || String(raw).trim();
}
let response;
if (!rows.length) {
  response = 'В базе документов пока ничего нет. Загрузите файлы через «Загрузка документов» на дашборде.';
} else {
  const NL = String.fromCharCode(10);
  const total = rows.length;
  const showLimit = 10000;
  const lines = rows.slice(0, showLimit).map((r, idx) => {
    const n = (r.chunks && r.chunks > 1) ? (' (' + r.chunks + ' фрагм.)') : '';
    const __num = (idx + 1) + '. ';
    const __label = cleanName(r.filename) + n;
    const __src = r.source || 'internal';
    const __did = (r.doc_id != null) ? String(r.doc_id) : '';
    // R8.83: номер «N. » — ВНЕ маркера (остаётся белым); кликабельна только
    // имя-метка (внутри [[DOC|...]] → ссылка).
    return __did ? (__num + '[[DOC|' + __src + '|' + encodeURIComponent(__did) + '|' + __label + ']]') : (__num + __label);
  });
  response = 'Загружено документов: ' + total + '.' + NL + lines.join(NL);
  if (total > showLimit) response += NL + '...и ещё ' + (total - showLimit) + '.';
}
// R8.84: псевдо-стриминг списка (cps 300). Скрытые маркеры [[DOC|…]] typewriter
// перепрыгивает (skip в тике) → длинный encoded id не создаёт пауз при печати.
return [{ json: { response, cps: 300 } }];

// R8.35: объединяем результаты от двух Поисков (через Merge append).
// Каждый item имеет поле source ('наш'|'внешний'). Чистим ошибки/пустоты,
// сортируем по similarity DESC, оставляем top 5.
const all = $input.all().map(i => i.json);
const clean = all.filter(r => r && !r.error && r.chunk_text && r.chunk_text.trim && r.chunk_text.trim().length > 0);
clean.sort((a, b) => (b.similarity || 0) - (a.similarity || 0));
const __pass = clean.filter(function (x) { return x.similarity === undefined || x.similarity >= 0.5; }); const top = (__pass.length ? __pass : clean).slice(0, 5);
return top.map(r => ({ json: r }));

function cleanName(raw){var s=String(raw||'').trim();var c=Math.max(s.lastIndexOf('/'),s.lastIndexOf('\\'));if(c>=0)s=s.slice(c+1);return s.split('_').join(' ').replace(/\s+/g,' ').trim();}
const row = ($input.first() && $input.first().json) || {};
const content = String(row.content || '').trim();
let response;
if (!content) {
  response = 'Не удалось загрузить содержимое документа — возможно, текст не был проиндексирован.';
} else {
  const fn = cleanName(row.filename) || 'Документ';
  const CAP = 1000000;
  let body = content, note = '';
  if (body.length > CAP) { body = body.slice(0, CAP); note = '\n\n…(показано ' + CAP + ' символов из ' + content.length + ')'; }
  response = '[[DOCHEAD|' + fn + ']]\n\n' + body + note;
}
// R8.95: пословный стриминг (wordMode) + адаптивная скорость — чтобы и маленький
// документ шёл «по словам» читаемо, и большой (до 1 млн символов) не полз минутами.
// cps ≈ длина/8 (≈8 сек на показ), в рамках [400, 100000].
const __cps = Math.max(400, Math.min(100000, Math.ceil(response.length / 8)));
return [{ json: { response, cps: __cps, wordMode: true } }];
